38	// downFileDir is the directory in which gcp-routes will look for a flag-file that
39	// indicates the route to the VIP should be withdrawn.
40	const downFileDir = "/run/cloud-routes"
41	
42	func init() {
43		rootCmd.AddCommand(runCmd)
44		runCmd.PersistentFlags().StringVar(&runOpts.rootMount, "root-mount", "/rootfs", "where the nodes root filesystem is mounted for writing down files or chrooting.")
45		runCmd.PersistentFlags().StringVar(&runOpts.healthCheckURL, "health-check-url", "", "HTTP(s) URL for the health check. The hostname is also used to determine the virtual IPs")
46	}
