48	type handler struct {
49		vips []string
50	}
51	
52	func runRunCmd(_ *cobra.Command, _ []string) error {
53		flag.Set("logtostderr", "true")
54		flag.Parse()
55	
56		// To help debugging, immediately log version
57		klog.Infof("Version: %+v (%s)", version.Raw, version.Hash)
58	
59		uri, err := url.Parse(runOpts.healthCheckURL)
60		if err != nil {
61			return fmt.Errorf("failed to parse health-check-url: %w", err)
62		}
63		if !uri.IsAbs() {
64			return fmt.Errorf("invalid URI %q (no scheme)", uri)
65		}
66	
67		handler, err := newHandler(uri)
68		if err != nil {
69			return err
70		}
71	
72		// The health check should always connect to localhost, not be load-balanced
73		uri.Host = net.JoinHostPort("localhost", uri.Port())
74	
75		httpCheck, err := checkers.NewHTTP(&checkers.HTTPConfig{
76			URL: uri,
77			Client: &http.Client{Transport: &http.Transport{
78				// #nosec G402
79				// health checks to https endpoints can use InsecureSkipVerify.
80				TLSClientConfig: &tls.Config{InsecureSkipVerify: true},
81			}},
82		})
83		if err != nil {
84			return fmt.Errorf("failed to create httpCheck: %w", err)
85		}
86		errCh := make(chan error)
87	
88		// careful: the timing here needs to correspond to the load balancer's
89		// parameters. We need to remove routes just after we've been removed
90		// as a backend in the load-balancer, and add routes before we've been
91		// re-added.
92		// see openshift/installer/data/data/gcp/network/lb-private.tf
93		// see openshift/installer/data/data/azure/vnet/internal-lb.tf
94		tracker := &healthTracker{
95			state:            unknownTrackerState,
96			ErrCh:            errCh,
97			SuccessThreshold: 1,
98			FailureThreshold: 8, // LB = 6 seconds, plus 10 seconds for propagation
99			OnFailure:        handler.onFailure,
100			OnSuccess:        handler.onSuccess,
101		}
102	
103		h := health.New()
104		h.AddChecks([]*health.Config{{
105			Name:       "dependency-check",
106			Checker:    httpCheck,
107			Interval:   time.Duration(2) * time.Second,
108			Fatal:      true,
109			OnComplete: tracker.OnComplete,
110		}})
111	
112		if err := h.Start(); err != nil {
113			return fmt.Errorf("failed to start heath checker: %w", err)
114		}
115	
116		c := make(chan os.Signal, 1)
117		signal.Notify(c, os.Interrupt)
118		go func() {
119			for sig := range c {
120				klog.Infof("Signal %s received: treating service as down", sig)
121				if err := handler.onFailure(); err != nil {
122					klog.Infof("Failed to mark service down on signal: %s", err)
123				}
124				os.Exit(0)
125			}
126		}()
127	
128		for {
129			select {
130			case err := <-errCh:
131				if err != nil {
132					return fmt.Errorf("error running health checker: %w", err)
133				}
134			}
135		}
136	}
