138	func newHandler(uri *url.URL) (*handler, error) {
139		addrs, err := net.LookupHost(uri.Hostname())
140		if err != nil {
141			return nil, fmt.Errorf("failed to lookup host %s: %w", uri.Hostname(), err)
142		}
143		if len(addrs) == 0 {
144			return nil, fmt.Errorf("hostname %s has no addresses, expected at least 1 - aborting", uri.Hostname())
145		}
146	
147		h := handler{
148			vips: addrs,
149		}
150		klog.Infof("Using VIPs %v", h.vips)
151		return &h, nil
152	}
