154	// onFailure: either stop the routes service, or write downfile
155	func (h *handler) onFailure() error {
156		for _, vip := range h.vips {
157			if err := writeVipStateFile(vip, "down"); err != nil {
158				return err
159			}
160			klog.Infof("healthcheck failed, created downfile %s.down", vip)
161			if err := removeVipStateFile(vip, "up"); err != nil {
162				return err
163			}
164		}
165		return nil
166	}
167	
168	// onSuccess: either start routes service, or remove down file
169	func (h *handler) onSuccess() error {
170		for _, vip := range h.vips {
171			if err := removeVipStateFile(vip, "down"); err != nil {
172				return err
173			}
174			klog.Infof("healthcheck succeeded, removed downfile %s.down", vip)
175			if err := writeVipStateFile(vip, "up"); err != nil {
176				return err
177			}
178		}
179		return nil
180	}
181	
182	func writeVipStateFile(vip, state string) error {
183		file := path.Join(runOpts.rootMount, downFileDir, fmt.Sprintf("%s.%s", vip, state))
184		// Disable gosec here to avoid throwing
185		// G306: Expect WriteFile permissions to be 0600 or less
186		// #nosec
187		err := os.WriteFile(file, nil, 0o644)
188		if err != nil {
189			return fmt.Errorf("failed to create file (%s): %w", file, err)
190		}
191		return nil
192	}
193	
194	func removeVipStateFile(vip, state string) error {
195		file := path.Join(runOpts.rootMount, downFileDir, fmt.Sprintf("%s.%s", vip, state))
196		err := os.Remove(file)
197		if err != nil && !os.IsNotExist(err) {
198			return fmt.Errorf("failed to remove file (%s): %w", file, err)
199		}
200		return nil
201	}
