203	type trackerState int
204	
205	const (
206		unknownTrackerState trackerState = iota
207		failedTrackerState
208		succeededTrackerState
209	)
210	
211	type healthTracker struct {
212		sync.Mutex
213	
214		state trackerState
215	
216		succeeded int
217		failed    int
218	
219		// ErrCh is used to collect errors
220		ErrCh chan<- error
221	
222		// SuccessThreshold is the number of consecutive success
223		SuccessThreshold int
224	
225		// FailureThreshold is the number of consecutive failure that trigger OnFailure func
226		FailureThreshold int
227	
228		// OnFailure is the function that is triggered when the health check is in FAILED state
229		// Non nil error are sent over the ErrCh
230		// Only one OnFailure function will be active at a time.
231		OnFailure func() error
232	
233		// OnSuccess is the function that is triggered when the health check is in SUCCEEDED state
234		// Non nil error are sent over the ErrCh
235		// Only one OnFailure function will be active at a time.
236		OnSuccess func() error
237	}
238	
239	func (sl *healthTracker) OnComplete(state *health.State) {
240		sl.Lock()
241		defer sl.Unlock()
242	
243		switch state.Status {
244		case "ok":
245			sl.failed = 0
246			sl.succeeded++
247			if sl.succeeded >= sl.SuccessThreshold {
248				if sl.state != succeededTrackerState {
249					klog.Info("Running OnSuccess trigger")
250					if err := sl.OnSuccess(); err != nil {
251						sl.ErrCh <- err
252					}
253				}
254				sl.state = succeededTrackerState
255			}
256		case "failed":
257			sl.succeeded = 0
258			sl.failed++
259			if sl.failed >= sl.FailureThreshold {
260				if sl.state != failedTrackerState {
261					klog.Info("Running OnFailure trigger")
262					if err := sl.OnFailure(); err != nil {
263						sl.ErrCh <- err
264					}
265				}
266				sl.state = failedTrackerState
267			}
268		}
269	}
