310	// syncMachineConfigPool will sync the machineconfig pool with the given key.
311	// This function is not meant to be invoked concurrently with the same key.
312	func (ctrl *Controller) syncMachineConfigPool(key string) error {
313		startTime := time.Now()
314		klog.V(4).Infof("Started syncing machineconfigpool %q (%v)", key, startTime)
315		defer func() {
316			klog.V(4).Infof("Finished syncing machineconfigpool %q (%v)", key, time.Since(startTime))
317		}()
318	
319		_, name, err := cache.SplitMetaNamespaceKey(key)
320		if err != nil {
321			return err
322		}
323		mcp, err := ctrl.mcpLister.Get(name)
324		if errors.IsNotFound(err) {
325			klog.V(2).Infof("MachineConfigPool %v has been deleted", key)
326			return nil
327		}
328		if err != nil {
329			return err
330		}
331	
332		pool := mcp.DeepCopy()
333		everything := metav1.LabelSelector{}
334		if reflect.DeepEqual(pool.Spec.MachineConfigSelector, &everything) {
335			return nil
336		}
337	
338		selector, err := metav1.LabelSelectorAsSelector(pool.Spec.MachineConfigSelector)
339		if err != nil {
340			return err
341		}
342	
343		imageSets, err := ctrl.imageSetLister.List(selector)
344		if err != nil {
345			return err
346		}
347		sort.SliceStable(imageSets, func(i, j int) bool { return imageSets[i].Name < imageSets[j].Name })
348	
349		if err := ctrl.syncPinnedImageSets(pool, imageSets); err != nil {
350			klog.Errorf("Error syncing pinned image sets: %v", err)
351			return ctrl.syncFailingStatus(pool, err)
352		}
353	
354		return ctrl.syncAvailableStatus(pool)

